use katana_tee_client::TeeQuoteResponse;
use starknet_rust_core::types::Felt;
const EXAMPLE_JSON: &str = r#"{
   "jsonrpc":"2.0",
   "id":1,
   "result":{"quote":"","prevStateRoot":"0x0","stateRoot":"0x5da4151adf86566185d11904106b9c682225978d65129a170704dad449f642d","prevBlockHash":"0x0","blockHash":"0x54d29b665f69e69f551fe33159ae4be707968c5b953ca9946701fd8633cb5bd",
   "prevBlockNumber":"0x800000000000011000000000000000000000000000000000000000000000000","blockNumber":"0x0",
   "messagesCommitment":"0x0","l2ToL1Messages":[],"l1ToL2Messages":[]}
}"#;

#[test]
fn test_parse_json_rpc_response() {
    let response = TeeQuoteResponse::from_json_str(EXAMPLE_JSON).unwrap();
    assert_eq!(response.block_number, Felt::ZERO);
    assert_eq!(response.block_hash, "0x54d29b665f69e69f551fe33159ae4be707968c5b953ca9946701fd8633cb5bd");
    assert_eq!(response.prev_block_number,Felt::MAX );
}

#[test]
fn test_quote_bytes() {
    let response = TeeQuoteResponse::from_json_str(EXAMPLE_JSON).unwrap();
    let bytes = response.quote_bytes().unwrap();
    // AMD SEV-SNP attestation report is 1184 bytes
    assert_eq!(bytes.len(), 1184);
    assert_eq!(&bytes[..8], &[0x05, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00]);
}

#[test]
fn test_parse_direct() {
    let direct_json = r#"{
        "quote": "0xabcd",
        "stateRoot": "0x123",
        "blockHash": "0x456",
        "blockNumber": "0x2a"
    }"#;
    let response = TeeQuoteResponse::from_json_str(direct_json).unwrap();
    assert_eq!(response.block_number, Felt::from_hex_unchecked("0x2a"));
}
